export class DomainError extends Error {}
export type LegalCaseCommand =
  | { type: "open"; caseId: string; client: string }
  | { type: "fileMotion"; motionId: string }
  | { type: "resolveMotion"; motionId: string }
  | { type: "close" };
export type LegalCaseEvent =
  | { type: "opened"; caseId: string; client: string }
  | { type: "motionFiled"; motionId: string }
  | { type: "motionResolved"; motionId: string }
  | { type: "closed" };
export type LegalCaseState =
  | { status: "none" }
  | { status: "open"; caseId: string; client: string; unresolved: number }
  | { status: "closed"; caseId: string };
export const initialState: LegalCaseState = { status: "none" };
export interface Decider<C, E, S> {
  initialState: S;
  decide: (c: C, s: S) => E[];
  evolve: (s: S, e: E) => S;
}
export function decide(c: LegalCaseCommand, s: LegalCaseState): LegalCaseEvent[] {
  switch (c.type) {
    case "open":
      if (s.status !== "none") throw new DomainError("already open");
      return [{ type: "opened", caseId: c.caseId, client: c.client }];
    case "fileMotion":
      if (s.status !== "open") throw new DomainError("not open");
      return [{ type: "motionFiled", motionId: c.motionId }];
    case "resolveMotion":
      if (s.status !== "open") throw new DomainError("not open");
      return [{ type: "motionResolved", motionId: c.motionId }];
    case "close":
      if (s.status !== "open") throw new DomainError("not open");
      if (s.unresolved > 0) throw new DomainError("unresolved motions");
      return [{ type: "closed" }];
    default: { const _: never = c; return _; }
  }
}
export function evolve(s: LegalCaseState, e: LegalCaseEvent): LegalCaseState {
  switch (e.type) {
    case "opened": return { status: "open", caseId: e.caseId, client: e.client, unresolved: 0 };
    case "motionFiled": return s.status === "open" ? { ...s, unresolved: s.unresolved + 1 } : s;
    case "motionResolved": return s.status === "open" ? { ...s, unresolved: Math.max(0, s.unresolved - 1) } : s;
    case "closed": return s.status === "open" ? { status: "closed", caseId: s.caseId } : s;
    default: { const _: never = e; return _; }
  }
}
export const LegalCaseDecider: Decider<LegalCaseCommand, LegalCaseEvent, LegalCaseState> = { initialState, decide, evolve };
