A Decider bundles pure decide and evolve functions plus an initial state. decide produces events from a command without I/O; evolve folds events into state. Invariants (like double-acknowledgement) are checked inside decide and surface as typed domain errors.

```typescript
export class InvariantError extends Error {}
export type DiscoveryRequestCommand =
  | { type: "issue"; requestId: string; topic: string }
  | { type: "acknowledge"; by: string }
  | { type: "produce"; documentId: string };
export type DiscoveryRequestEvent =
  | { type: "issued"; requestId: string; topic: string }
  | { type: "acknowledged"; by: string }
  | { type: "produced"; documentId: string };
export type DiscoveryRequestState =
  | { status: "none" }
  | { status: "issued"; requestId: string; acknowledgedBy: string | null; produced: number };
export const initialState: DiscoveryRequestState = { status: "none" };
export interface Decider<C, E, S> { initialState: S; decide: (c: C, s: S) => E[]; evolve: (s: S, e: E) => S }
export function decide(c: DiscoveryRequestCommand, s: DiscoveryRequestState): DiscoveryRequestEvent[] {
  switch (c.type) {
    case "issue":
      if (s.status !== "none") throw new InvariantError("already issued");
      return [{ type: "issued", requestId: c.requestId, topic: c.topic }];
    case "acknowledge":
      if (s.status !== "issued") throw new InvariantError("not issued");
      if (s.acknowledgedBy !== null) throw new InvariantError("already acknowledged");
      return [{ type: "acknowledged", by: c.by }];
    case "produce":
      if (s.status !== "issued") throw new InvariantError("not issued");
      return [{ type: "produced", documentId: c.documentId }];
    default: { const _: never = c; return _; }
  }
}
export function evolve(s: DiscoveryRequestState, e: DiscoveryRequestEvent): DiscoveryRequestState {
  switch (e.type) {
    case "issued": return { status: "issued", requestId: e.requestId, acknowledgedBy: null, produced: 0 };
    case "acknowledged": return s.status === "issued" ? { ...s, acknowledgedBy: e.by } : s;
    case "produced": return s.status === "issued" ? { ...s, produced: s.produced + 1 } : s;
    default: { const _: never = e; return _; }
  }
}
export const DiscoveryRequestDecider: Decider<DiscoveryRequestCommand, DiscoveryRequestEvent, DiscoveryRequestState> = { initialState, decide, evolve };
