export type RetainerAgreementCommand =
  | { type: "sign"; agreementId: string; client: string; initialBalance: number }
  | { type: "replenish"; amount: number }
  | { type: "terminate" };
export type RetainerAgreementEvent =
  | { type: "signed"; agreementId: string; client: string; balance: number }
  | { type: "replenished"; amount: number }
  | { type: "terminated" };
export type RetainerAgreementState =
  | { status: "none" }
  | { status: "active"; agreementId: string; balance: number }
  | { status: "terminated" };
export const initialState: RetainerAgreementState = { status: "none" };
export interface Decider<C, E, S> { initialState: S; decide: (c: C, s: S) => E[]; evolve: (s: S, e: E) => S }
export function decide(c: RetainerAgreementCommand, s: RetainerAgreementState): RetainerAgreementEvent[] {
  switch (c.type) {
    case "sign":
      if (s.status !== "none") throw new AgreementError("already signed");
      if (c.initialBalance < 0) throw new AgreementError("negative");
      return [{ type: "signed", agreementId: c.agreementId, client: c.client, balance: c.initialBalance }];
    case "replenish":
      if (s.status !== "active") throw new AgreementError("not active");
      if (c.amount <= 0) throw new AgreementError("non-positive");
      return [{ type: "replenished", amount: c.amount }];
    case "terminate":
      if (s.status !== "active") throw new AgreementError("not active");
      if (s.balance !== 0) throw new AgreementError("balance outstanding");
      return [{ type: "terminated" }];
    default: { const _: never = c; return _; }
  }
}
export function evolve(s: RetainerAgreementState, e: RetainerAgreementEvent): RetainerAgreementState {
  switch (e.type) {
    case "signed": return { status: "active", agreementId: e.agreementId, balance: e.balance };
    case "replenished": return s.status === "active" ? { ...s, balance: s.balance + e.amount } : s;
    case "terminated": return { status: "terminated" };
    default: { const _: never = e; return _; }
  }
}
export const RetainerDecider: Decider<RetainerAgreementCommand, RetainerAgreementEvent, RetainerAgreementState> = { initialState, decide, evolve };
