export type SettlementOfferEvent =
  | { type: "offerMade"; caseId: string; amount: number; offerId: string }
  | { type: "offerRevised"; caseId: string; offerId: string; amount: number }
  | { type: "offerWithdrawn"; caseId: string; offerId: string }
  | { type: "offerAccepted"; caseId: string; offerId: string };
export type SettlementView = {
  caseId: string;
  bestOffer: number;
  revisions: number;
  status: "open" | "accepted" | "withdrawn";
};
export const emptyView = (caseId: string): SettlementView => ({
  caseId,
  bestOffer: 0,
  revisions: 0,
  status: "open",
});
export function project(view: SettlementView, e: SettlementOfferEvent): SettlementView {
  switch (e.type) {
    case "offerMade":
      return { ...view, bestOffer: Math.max(view.bestOffer, e.amount) };
    case "offerRevised":
      return { ...view, bestOffer: Math.max(view.bestOffer, e.amount), revisions: view.revisions + 1 };
    case "offerWithdrawn":
      return { ...view, status: "withdrawn" };
    case "offerAccepted":
      return { ...view, status: "accepted" };
    default: { const _: never = e; return view; }
  }
}
export function projectAll(caseId: string, events: SettlementOfferEvent[]): SettlementView {
  return events.reduce<SettlementView>(project, emptyView(caseId));
}
