A Snapshot stores the aggregate state tagged with a schema version. On load we run upgrader functions in sequence until we reach CURRENT_VERSION, then assert the shape matches.

```typescript
export interface Snapshot<S> { version: number; state: S }
interface LegalCaseV1 { status: "open" | "closed"; caseId: string; client: string }
interface LegalCaseV2 { status: "open" | "closed"; caseId: string; client: string; priority: "low" | "normal" | "high" }
export type CurrentLegalCase = LegalCaseV2;
export const CURRENT_VERSION = 2;
function v1Tov2(s: LegalCaseV1): LegalCaseV2 { return { ...s, priority: "normal" }; }
export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentLegalCase> {
  let version = snap.version;
  let state = snap.state;
  if (version === 1) { state = v1Tov2(state as LegalCaseV1); version = 2; }
  if (version !== CURRENT_VERSION) throw new Error("unsupported snapshot version");
  return { version, state: state as CurrentLegalCase };
}
