  let v = raw.version;
  let s: unknown = raw.state;
  if (v === 1) { s = v1Tov2(s as RetainerV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as RetainerV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error(`unexpected snapshot version ${v}`);
  return { version: v, state: s as CurrentRetainer };
}
export function loadSnapshot(raw: Snapshot<unknown>): CurrentRetainer {
  const snap: Snapshot<CurrentRetainer> = upgradeSnapshot(raw);
  return snap.state;
}
