export interface EventStore<E> { readBatch(from: bigint, size: number): Promise<Stored<E>[]> }
export interface ReadStore { persist(caseId: string, view: SettlementView): Promise<void> }
export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  eventStore: EventStore<SettlementOfferEvent>;
  readStore: ReadStore;
  caseIdOf: (e: SettlementOfferEvent) => string;
}): Promise<void> {
  let cursor = opts.from;
  const views: Record<string, SettlementView> = {};
  while (true) {
    const batch = await opts.eventStore.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const rec of batch) {
      const id = opts.caseIdOf(rec.event);
      views[id] = project(views[id] ?? emptyView(id), rec.event);
      await opts.readStore.persist(id, views[id]);
      cursor = rec.revision + 1n;
    }
  }
